#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=5e6+5,mod=998244353;
int ksm(int a,int b,int p) {
	int ans=1;
	while(b) {
		if(b&1) {
			ans=(ans*a)%p;
		}
		a=(a*a)%p;
		b>>=1;
	}
	return ans;
}
int c1[maxn],c2[maxn],x;
void sx() {
	for(int i=1; i<=x; i++) {
		c1[i]=c1[i-1]*i%mod;
	}
	c2[x]=ksm(c1[x],mod-2,mod);
	for(int i=x-1; i>=1; i--) {
		c2[i]=c2[i+1]*(i+1)%mod;
	}
}
int C(int n,int m) {
	if(m<0||m>n) {
		return 0;
	}
	return c1[n]*c2[m]%mod*c2[n-m]%mod;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int t,n,m,ans=0;
	cin>>t>>x;
	c1[0]=c2[0]=1;
	sx();
	while(t--) {
		cin>>n>>m;
		ans^=C(n,m);
	}
	cout<<ans;
	return 0;
}
